#' Latent Biomarker Construct + Cox Regression
#'
#' Estimate a single reflective latent biomarker construct from 3+ indicators 
#' and relate it to a right-censored survival outcome via Cox regression. 
#' Auto-selects MLR (continuous) or WLSMV (ordinal/binary) estimation. Refuses 
#' inappropriate inputs with explanatory messages.
#'
#' @examples
#' \donttest{
#' data('histopathology', package='ClinicoPath')
#' ClinicoPath::latentbiomarker(
#'     data = histopathology,
#'     dep_time = "OverallTime",
#'     dep_event = "Outcome",
#'     event_level = "1",
#'     indicators = c("MeasurementA", "MeasurementB", "Measurement1"),
#'     reflective_confirmed = TRUE
#' )
#'}
#' @param data The data as a data frame.
#' @param dep_time .
#' @param dep_event .
#' @param event_level .
#' @param indicators .
#' @param adjusters .
#' @param indicator_types .
#' @param reflective_confirmed .
#' @param factor_score_method .
#' @param standardize_scores .
#' @param factor_score_name .
#' @param km_strata .
#' @param show_plot_km .
#' @param show_plot_loadings .
#' @param show_plot_path .
#' @param show_diagnostics .
#' @param show_r_code .
#' @return A results object containing:
#' \tabular{llllll}{
#'   \code{results$notices} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$summaryTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$loadingsTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$reliabilityTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$fitTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$coxTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$phTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$kmPlot} \tab \tab \tab \tab \tab an image \cr
#'   \code{results$loadingsPlot} \tab \tab \tab \tab \tab an image \cr
#'   \code{results$pathPlot} \tab \tab \tab \tab \tab an image \cr
#'   \code{results$miTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$rCode} \tab \tab \tab \tab \tab a preformatted \cr
#'   \code{results$save_factor_scores} \tab \tab \tab \tab \tab an output \cr
#' }
#'
#' Tables can be converted to data frames with \code{asDF} or \code{\link{as.data.frame}}. For example:
#'
#' \code{results$summaryTable$asDF}
#'
#' \code{as.data.frame(results$summaryTable)}
#'
#' @export
latentbiomarker <- function(
    data,
    dep_time = NULL,
    dep_event = NULL,
    event_level,
    indicators = NULL,
    adjusters = NULL,
    indicator_types = "auto",
    reflective_confirmed = FALSE,
    factor_score_method = "regression",
    standardize_scores = TRUE,
    factor_score_name = "biomarker_factor",
    km_strata = "tertile",
    show_plot_km = TRUE,
    show_plot_loadings = TRUE,
    show_plot_path = TRUE,
    show_diagnostics = TRUE,
    show_r_code = FALSE) {

    if ( ! requireNamespace("jmvcore", quietly=TRUE))
        stop("latentbiomarker requires jmvcore to be installed (restart may be required)")

    if ( ! missing(dep_time)) dep_time <- jmvcore::resolveQuo(jmvcore::enquo(dep_time))
    if ( ! missing(dep_event)) dep_event <- jmvcore::resolveQuo(jmvcore::enquo(dep_event))
    if ( ! missing(indicators)) indicators <- jmvcore::resolveQuo(jmvcore::enquo(indicators))
    if ( ! missing(adjusters)) adjusters <- jmvcore::resolveQuo(jmvcore::enquo(adjusters))
    if (missing(data))
        data <- jmvcore::marshalData(
            parent.frame(),
            `if`( ! missing(dep_time), dep_time, NULL),
            `if`( ! missing(dep_event), dep_event, NULL),
            `if`( ! missing(indicators), indicators, NULL),
            `if`( ! missing(adjusters), adjusters, NULL))


    options <- latentbiomarkerOptions$new(
        dep_time = dep_time,
        dep_event = dep_event,
        event_level = event_level,
        indicators = indicators,
        adjusters = adjusters,
        indicator_types = indicator_types,
        reflective_confirmed = reflective_confirmed,
        factor_score_method = factor_score_method,
        standardize_scores = standardize_scores,
        factor_score_name = factor_score_name,
        km_strata = km_strata,
        show_plot_km = show_plot_km,
        show_plot_loadings = show_plot_loadings,
        show_plot_path = show_plot_path,
        show_diagnostics = show_diagnostics,
        show_r_code = show_r_code)

    analysis <- latentbiomarkerClass$new(
        options = options,
        data = data)

    analysis$run()

    analysis$results
}

